// actionState collapses the coordinator phase + staged flag into the slot
// state. Mirrored in JS renderAction().
func actionState(d SystemPageData) string {
	switch d.Phase {
	case "downloading", "staged", "applying", "checking":
		return d.Phase
	}
	if d.HasStaged {
		return "staged"
	}
	return "idle"
}

func pctWidth(p int) string {
	if p < 0 {
		p = 0
	}
	if p > 100 {
		p = 100
	}
	return "width:" + strconv.Itoa(p) + "%"
}

func pctText(p int) string { return strconv.Itoa(p) + "%" }

